    public void scanLocalNetwork(String subnet, int port, boolean useSsl, DeviceScanCallback scanCallback) {
        new Thread(() -> {
            for (int i = 1; i < 255; i++) {
                final String ip = subnet + "." + i;
                try {
                    InetAddress address = InetAddress.getByName(ip);
                    if (address.isReachable(500)) {
                        pingDevice(ip, port, useSsl, new ApiCallback<DevicePingResponse>() {
                            @Override
                            public void onSuccess(DevicePingResponse response) {
                                scanCallback.onDeviceFound(ip, port, response);
                            }

                            @Override
                            public void onFailure(IoTNetworkException error) {
                                // Not an IoT device, ignore
                            }
                        });
                    }
                } catch (IOException e) {
                    // Host unreachable, continue scanning
                }
            }
            scanCallback.onScanComplete();
        }, "NetworkScanThread").start();
    }

