    public void uploadFirmware(String deviceId, String path, byte[] firmwareData, String firmwareVersion,
                               ProgressCallback progressCallback, ApiCallback<FirmwareUpdateResponse> callback) {
        DeviceConnectionInfo info = getDeviceInfo(deviceId);
        if (info == null) {
            callback.onFailure(new IoTNetworkException("Device not registered: " + deviceId));
            return;
        }

        String url = info.buildUrl(path);
        MediaType octetStream = MediaType.parse("application/octet-stream");

        RequestBody body = new ProgressRequestBody(
                RequestBody.create(firmwareData, octetStream),
                progressCallback
        );

        Request request = new Request.Builder()
                .url(url)
                .post(body)
                .addHeader("X-Device-Id", deviceId)
                .addHeader("X-Firmware-Version", firmwareVersion)
                .addHeader("Content-Type", "application/octet-stream")
                .build();

        OkHttpClient firmwareClient = localClient.newBuilder()
                .writeTimeout(120, TimeUnit.SECONDS)
                .readTimeout(120, TimeUnit.SECONDS)
                .build();

        executeAsync(firmwareClient, request, FirmwareUpdateResponse.class, callback);
    }

