    private <T> void executeAsync(OkHttpClient client, Request request, Class<T> responseType, ApiCallback<T> callback) {
        client.newCall(request).enqueue(new Callback() {
            @Override
            public void onFailure(Call call, IOException e) {
                Log.e(TAG, "Request failed: " + request.url(), e);
                callback.onFailure(new IoTNetworkException("Network request failed: " + e.getMessage(), e));
            }

            @Override
            public void onResponse(Call call, Response response) {
                try (ResponseBody responseBody = response.body()) {
                    if (!response.isSuccessful()) {
                        String errorBody = responseBody != null ? responseBody.string() : "No response body";
                        callback.onFailure(new IoTNetworkException(
                                "HTTP " + response.code() + ": " + errorBody, response.code()));
                        return;
                    }

                    if (responseType == Void.class || responseType == void.class) {
                        callback.onSuccess(null);
                        return;
                    }

                    if (responseBody == null) {
                        callback.onFailure(new IoTNetworkException("Empty response body"));
                        return;
                    }

                    String json = responseBody.string();
                    T result = gson.fromJson(json, responseType);
                    callback.onSuccess(result);
                } catch (IOException e) {
                    callback.onFailure(new IoTNetworkException("Failed to read response", e));
                } catch (Exception e) {
                    callback.onFailure(new IoTNetworkException("Failed to parse response", e));
                }
            }
        });
    }

    private <T> T executeSync(OkHttpClient client, Request request, Class<T> responseType) throws IoTNetworkException {
        try {
            Response response = client.newCall(request).execute();
            try (ResponseBody responseBody = response.body()) {
                if (!response.isSuccessful()) {
                    String errorBody = responseBody != null ? responseBody.string() : "No response body";
                    throw new IoTNetworkException("HTTP " + response.code() + ": " + errorBody, response.code());
                }

                if (responseType == Void.class || responseType == void.class) {
                    return null;
                }

                if (responseBody == null) {
                    throw new IoTNetworkException("Empty response body");
                }

                String json = responseBody.string();
                return gson.fromJson(json, responseType);
            }
        } catch (IOException e) {
            throw new IoTNetworkException("Network request failed: " + e.getMessage(), e);
        }
    }

