// ProgressRequestBody.java - For firmware upload progress
// ============================================================
package com.iotmanager.network;

import java.io.IOException;

import okhttp3.MediaType;
import okhttp3.RequestBody;
import okio.Buffer;
import okio.BufferedSink;
import okio.ForwardingSink;
import okio.Okio;
import okio.Sink;

public class ProgressRequestBody extends RequestBody {

    private final RequestBody delegate;
    private final ProgressCallback progressCallback;

    public ProgressRequestBody(RequestBody delegate, ProgressCallback progressCallback) {
        this.delegate = delegate;
        this.progressCallback = progressCallback;
    }

    @Override
    public MediaType contentType() {
        return delegate.contentType();
    }

    @Override
    public long contentLength() throws IOException {
        return delegate.contentLength();
    }

    @Override
    public void writeTo(BufferedSink sink) throws IOException {
        long totalBytes = contentLength();
        CountingSink countingSink = new CountingSink(sink, totalBytes);
        BufferedSink bufferedSink = Okio.buffer(countingSink);
        delegate.writeTo(bufferedSink);
        bufferedSink.flush();
    }

    private class CountingSink extends ForwardingSink {
        private long bytesWritten = 0;
        private final long totalBytes;

        CountingSink(Sink delegate, long totalBytes) {
            super(delegate);
            this.totalBytes = totalBytes;
        }

        @Override
        public void write(Buffer source, long byteCount) throws IOException {
            super.write(source, byteCount);
            bytesWritten += byteCount;
            if (progressCallback != null && totalBytes > 0) {
                int progress = (int) ((bytesWritten * 100) / totalBytes);
                progressCallback.onProgress(bytesWritten, totalBytes, progress);
            }
        }
    }
}

