package com.iotmanager.network;

public class IoTNetworkException extends Exception {
    private int httpStatusCode = -1;

    public IoTNetworkException(String message) {
        super(message);
    }

    public IoTNetworkException(String message, Throwable cause) {
        super(message, cause);
    }

    public IoTNetworkException(String message, int httpStatusCode) {
        super(message);
        this.httpStatusCode = httpStatusCode;
    }

    public int getHttpStatusCode() {
        return httpStatusCode;
    }

    public boolean isHttpError() {
        return httpStatusCode > 0;
    }

    public boolean isClientError() {
        return httpStatusCode >= 400 && httpStatusCode < 500;
    }

    public boolean isServerError() {
        return httpStatusCode >= 500;
    }

    public boolean isUnauthorized() {
        return httpStatusCode == 401;
    }

    public boolean isForbidden() {
        return httpStatusCode == 403;
    }

    public boolean isNotFound() {
        return httpStatusCode == 404;
    }
}

