package com.iotmanager.network;

import java.util.List;

public class DeviceListResponse {
    private List<DeviceInfo> devices;
    private int total;
    private int page;
    private int pageSize;

    public List<DeviceInfo> getDevices() { return devices; }
    public void setDevices(List<DeviceInfo> devices) { this.devices = devices; }
    public int getTotal() { return total; }
    public void setTotal(int total) { this.total = total; }
    public int getPage() { return page; }
    public void setPage(int page) { this.page = page; }
    public int getPageSize() { return pageSize; }
    public void setPageSize(int pageSize) { this.pageSize = pageSize; }

    public static class DeviceInfo {
        private String id;
        private String name;
        private String type;
        private String firmwareVersion;
        private String macAddress;
        private boolean online;
        private long registeredAt;
        private long lastSeenAt;

        public String getId() { return id; }
        public void setId(String id) { this.id = id; }
        public String getName() { return name; }
        public void setName(String name) { this.name = name; }
        public String getType() { return type; }
        public void setType(String type) { this.type = type; }
        public String getFirmwareVersion() { return firmwareVersion; }
        public void setFirmwareVersion(String firmwareVersion) { this.firmwareVersion = firmwareVersion; }
        public String getMacAddress() { return macAddress; }
        public void setMacAddress(String macAddress) { this.macAddress = macAddress; }
        public boolean isOnline() { return online; }
        public void setOnline(boolean online) { this.online = online; }
        public long getRegisteredAt() { return registeredAt; }
        public void setRegisteredAt(long registeredAt) { this.registeredAt = registeredAt; }
        public long getLastSeenAt() { return lastSeenAt; }
        public void setLastSeenAt(long lastSeenAt) { this.lastSeenAt = lastSeenAt; }
    }
}

