// IoTDeviceManager.java - High-level convenience class
// ============================================================
package com.iotmanager.network;

import android.content.Context;
import android.os.Handler;
import android.os.Looper;
import android.util.Log;

import java.util.HashMap;
import java.util.Map;

public class IoTDeviceManager {

    private static final String TAG = "IoTDeviceManager";
    private final IoTHttpClient client;
    private final Handler mainHandler;

    public IoTDeviceManager(Context context, String cloudBaseUrl, String authToken) {
        this.client = IoTHttpClient.getInstance(context);
        this.client.setCloudBaseUrl(cloudBaseUrl);
        this.client.setAuthToken(authToken);
        this.mainHandler = new Handler(Looper.getMainLooper());
    }

    public void updateAuthToken(String newToken) {
        client.setAuthToken(newToken);
    }

    // ============================================================
    // Cloud Operations
    // ============================================================

    public void fetchDeviceList(int page, int pageSize, ApiCallback<DeviceListResponse> callback) {
        String endpoint = "/api/v1/devices?page=" + page + "&pageSize=" + pageSize;
        client.cloudGet(endpoint, DeviceListResponse.class, wrapCallbackToMainThread(callback));
    }

    public void registerDeviceToCloud(String deviceName, String deviceType, String macAddress,
                                      ApiCallback<DeviceListResponse.DeviceInfo> callback) {
        Map<String, String> body = new HashMap<>();
        body.put("name", deviceName);
        body.put("type", deviceType);
        body.put("macAddress", macAddress);

        client.cloudPost("/api/v1/devices", body, DeviceListResponse.DeviceInfo.class,
                wrapCallbackToMainThread(callback));
    }

    public void removeDeviceFromCloud(String deviceId, ApiCallback<Void> callback) {
        client.cloudDelete("/api/v1/devices/" + deviceId, Void.class, wrapCallbackToMainThread(callback));
    }

    // ============================================================
    // Local Device Operations
    // ============================================================

    public void connectToLocalDevice(String deviceId, String ipAddress, int port, boolean useSsl) {
        client.registerDevice(deviceId, ipAddress, port, useSsl);
        Log.i(TAG, "Registered local device: " + deviceId + " at " + ipAddress + ":" + port +
                " (SSL: " + useSsl + ")");
    }

    public void disconnectLocalDevice(String deviceId) {
        client.unregisterDevice(deviceId);
        Log.i(TAG, "Unregistered local device: " + deviceId);
    }

    public void getDeviceStatus(String deviceId, ApiCallback<DeviceStatus> callback) {
        client.deviceGet(deviceId, "/api/status", DeviceStatus.class, wrapCallbackToMainThread(callback));
    }

    public void sendCommand(String deviceId, String command, Map<String, Object> params,
                            ApiCallback<DeviceCommandResponse> callback) {
        DeviceCommand cmd = new DeviceCommand(command, params);
        client.devicePost(deviceId, "/api/command", cmd, DeviceCommandResponse.class,
                wrapCallbackToMainThread(callback));
    }

    public void updateDeviceConfig(String deviceId, Map<String, Object> config,
                                   ApiCallback<DeviceCommandResponse> callback) {
        client.devicePut(deviceId, "/api/config", config, DeviceCommandResponse.class,
                wrapCallbackToMainThread(callback));
    }

    public void updateFirmware(String deviceId, byte[] firmwareData, String version,
                               ProgressCallback progressCallback, ApiCallback<FirmwareUpdateResponse> callback) {
        ProgressCallback mainThreadProgress = (bytesWritten, totalBytes, percentComplete) ->
                mainHandler.post(() -> progressCallback.onProgress(bytesWritten, totalBytes, percentComplete));

        client.uploadFirmware(deviceId, "/api/firmware/update", firmwareData, version,
                mainThreadProgress, wrapCallbackToMainThread(callback));
    }

    // ============================================================
    // Discovery
    // ============================================================

    public void discoverDevices(String subnet, int port, boolean useSsl, DeviceScanCallback callback) {
        if (!client.isOnWifi()) {
            Log.w(TAG, "Not on WiFi, local device discovery may not work");
        }

        DeviceScanCallback mainThreadCallback = new DeviceScanCallback() {
            @Override
            public void onDeviceFound(String ipAddress, int port, DevicePingResponse response) {
                mainHandler.post(() -> callback.onDeviceFound(ipAddress, port, response));
            }

            @Override
            public void onScanComplete() {
                mainHandler.post(callback::onScanComplete);
            }
        };

        client.scanLocalNetwork(subnet, port, useSsl, mainThreadCallback);
    }

    public void pingDevice(String ipAddress, int port, boolean useSsl, ApiCallback<DevicePingResponse> callback) {
        client.pingDevice(ipAddress, port, useSsl, wrapCallbackToMainThread(callback));
    }

    // ============================================================
    // Utility
    // ============================================================

    public boolean isNetworkAvailable() {
        return client.isNetworkAvailable();
    }

    public boolean isOnWifi() {
        return client.isOnWifi();
    }

    public void shutdown() {
        client.shutdown();
    }

    private <T> ApiCallback<T> wrapCallbackToMainThread(ApiCallback<T> callback) {
        return new ApiCallback<T>() {
            @Override
            public void onSuccess(T response) {
                mainHandler.post(() -> callback.onSuccess(response));
            }

            @Override
            public void onFailure(IoTNetworkException error) {
                mainHandler.post(() -> callback.onFailure(error));
            }
        };
    }
}

